use std::io;

fn read_line() -> String {
    let mut input_line = String::new();
    io::stdin().read_line(&mut input_line).unwrap();
    return String::from(input_line.trim());
}

fn digits(mut n: u64) -> u64 {
    let mut count = 0u64;
    while n > 0 {
        count += 1;
        n /= 10;
    }
    return count;
}

fn main() {
    let n: u64 = read_line().parse().unwrap();

    let d = digits(n);
    let mut nums_counted = 0u64;
    let mut nines = 9u64;
    let mut res = 0u64;
    for i in 1 .. d {
        let cur_len = nines - nums_counted;
        nines = nines * 10 + 9;
        res += cur_len * i;
        nums_counted += cur_len;
    }

    let cur_len = n - nums_counted;
    res += cur_len * d;

    println!("{}", res);
}
